Actually, new code contains exactly the same retry (see `retry in case of fragmentation` comment)
```cpp
    roundSize = BucketingStrategy::RoundAllocSizeForBucket(bucket_id);
    if (!MemoryIsAvalable(roundSize))
      ReleaseAllNoLock(false);

    void *ret = nullptr;
    auto e = contextHelper_->Malloc(&ret, roundSize);
    if (e) {
      // retry in case of fragmentation
      ReleaseAllNoLock(false);
      e = contextHelper_->Malloc(&ret, roundSize);
      if (e) {
        const std::string err(
#if MXNET_USE_CUDA
        dev_type_ == Context::kGPU?
           cudaGetErrorString(static_cast<cudaError_t>(e)) :
#endif
           std::strerror(errno));

        LOG(FATAL) << "Memory allocation failed " << err;
      }
    }

    UNSET_DEVICE(device_store);
    used_memory_ += roundSize;
```

As you could see, in that part I am using `ReleaseAllNoLock(false)` twice: 

- when the amount of free memory is below some threshold
- after unsuccessful first attempt to allocate memory.
After each of these two calls, we try to allocate memory by `contextHelper_->Malloc(&ret, roundSize);`

Previously, we had exactly the same:
```cpp
    size_t free, total;
    cudaMemGetInfo(&free, &total);
    if (free <= total * reserve_ / 100 || size > free - total * reserve_ / 100)
      ReleaseAll();

    void* ret = nullptr;
    cudaError_t e = cudaMalloc(&ret, size);
    if (e != cudaSuccess) {
      if (e == cudaErrorMemoryAllocation) {
        ReleaseAll();
        e = cudaMalloc(&ret, size);
        if (e != cudaSuccess && e != cudaErrorCudartUnloading) {
          LOG(FATAL) << "cudaMalloc retry failed: " << cudaGetErrorString(e);
        }
      } else if (e != cudaErrorCudartUnloading) {
        LOG(FATAL) << "cudaMalloc failed: " << cudaGetErrorString(e);
      }
    }
    used_memory_ += size;
```

