if you want to use the build-in class `BaseConfigurator`, we could add some code to confirm the custom json encoder is a sub class of `json.encoder.JSONEncoder`:
```python3
def configure_from_file(file_name, override_root_logger=True, use_structured_logger=True):
    """your comment"""
       with open(file_name) as config_file:
        config = yaml.load(config_file)
    for name, handler in config.get('handlers', {}).items():
        if 'json_encoder_class' in handler:
            json_encoder_config = logging.config.BaseConfigurator({})
            custom_encoder = json_encoder_config.resolve(handler['json_encoder_class'])
            if not issubclass(custom_encoder, json.encoder.JSONEncoder):
                raise TypeError("Invalid json encoder class {}, please use the class based on json.encoder.JSONEncoder!".format(custom_encoder))
            config['handlers'][name]['json_encoder_class'] = custom_encoder

    configure_from_dict(config, override_root_logger)
```

